INSERT INTO `discuss` VALUES (1823159034694897665, 1823159034694897664, '立方体的体积计算', '如何计算立方体的体积？公式是什么？', '2024-08-13 11:35:23', '2024-08-01 12:53:00');
INSERT INTO `discuss` VALUES (1823182479583465472, 1822964565643108352, '如何判断两条直线在空间中平行？', '今天课上老师讲到两条直线在空间中平行的条件，但我还是有些困惑。老师提到可以通过向量的方向判断，但我不太明白具体怎么操作。有人能详细解释一下吗？', '2024-08-13 10:19:11', '2024-08-07 12:52:57');
INSERT INTO `discuss` VALUES (1823201416975085569, 1823201416975085568, '求学霸救救！怎么判断两个平面平行？', '老师讲解了两个平面平行的条件，但我还是有些不明白。老师提到可以通过法向量判断，但我不太清楚具体怎么操作。有人能详细解释一下吗？', '2024-08-13 11:35:50', '2024-08-14 12:52:54');
INSERT INTO `discuss` VALUES (1823201440844869633, 1823201440844869632, '正四面体的体积', '正四面体的体积公式是什么？如何推导？', '2024-08-13 12:52:47', '2024-08-13 12:52:51');
INSERT INTO `discuss` VALUES (1823201465083752449, 1823201465083752448, '圆锥体被平面截出的截面形状是什么样的？', '老师讲到圆锥体被一个平面截出的截面形状，但我对不同情况下的截面形状还是有些模糊。比如，如果平面与圆锥体的轴成一定角度，截面会是什么形状？希望有人能帮我解答。', '2024-08-13 12:53:38', '2024-08-13 12:53:41');
INSERT INTO `discuss` VALUES (1823220216164356097, 1823220216164356096, '正方体的对角线长度', '正方体的对角线长度如何计算？公式是什么？', '2024-08-13 12:54:00', '2024-08-13 12:54:03');
INSERT INTO `discuss` VALUES (1823220399098925054, 1823220399098925056, '三棱锥的几何题我一直不懂，有没有人能指点我一二', '我遇到了好几个这种题目，脑子想不出图形，实在没有方法写，求救', '2024-08-04 18:44:17', '2024-08-14 18:44:23');
INSERT INTO `discuss` VALUES (1823220399098925057, 1823220399098925056, '如何计算圆柱体的体积？', '在今天的几何课上，我们学习了圆柱体的体积公式 。虽然老师讲解了公式的推导过程，但我还是不太理解。能不能有人用一个具体的例子来解释一下？', '2024-08-03 12:54:24', '2024-08-08 12:54:29');
INSERT INTO `discuss` VALUES (1823220456762216449, 1823220456762216448, '怎么判断一个点在不在平面上？求助！', '在今天的课上，老师讲解了判断一个点是否在一个平面上的方法，但我对平面方程的概念不太熟悉。有人能详细解释一下如何通过平面方程判断一个点是否在平面上吗？', '2024-08-02 12:55:00', '2024-08-07 12:55:04');
