INSERT INTO `knowledge_point` VALUES (0, '  <div>             <h4>&emsp;&emsp;1.&emsp;定义：</h4>             <p>               &emsp;&emsp;正方体（或称为立方体）是一个六个面都是正方形的特殊长方体，其中所有棱的长度都相等。             </p>             <br />             <h4>&emsp;&emsp;2.&emsp; 面与棱：</h4>             <p>               &emsp;&emsp;&emsp;（1）               <strong>面：</strong>正方体有6个面，每个面都是一个正方形。             </p>             <p>               &emsp;&emsp;&emsp;（2）               <strong>棱：</strong               >正方体有12条棱，每条棱连接两个面。由于所有棱的长度都相等，因此正方体具有高度的对称性。             </p>             <p>               &emsp;&emsp;&emsp;（3）               <strong>顶点：</strong>正方体有8个顶点，每个顶点由三条棱相交而成。             </p>             <p>               &emsp;&emsp;&emsp;（4）               <strong>底面：</strong>正方体的底面是6个面中的4个面，每个底面都是正方形。             </p>             <br />             <h4>&emsp;&emsp;3.&emsp; 对角线：</h4>             <p>               &emsp;&emsp;&emsp;（1）               <strong> 面对角线：</strong               >连接正方体同一面上的两个不相邻顶点的线段称为面对角线，每条面对角线都是正方形的对角线。             </p>             <p>               &emsp;&emsp;&emsp;（2）               <strong> 体对角线：</strong               >连接正方体两个不相邻顶点的线段称为体对角线。正方体有4条体对角线，每条体对角线都连接了正方体的相对顶点。体对角线的长度可以通过三维空间中的距离公式计算，对于边长为a的正方体，体对角线的长度为<span                 >\\sqrt{a^{2} + a^{2} + a^{2}} = \\sqrt{3}a</span               >             </p>             <br />             <h4>&emsp;&emsp;4.&emsp; 表面积与体积：</h4>             <p>               &emsp;&emsp;&emsp;（1）               <strong> 表面积：</strong               >连正方体的表面积是其所有面的面积之和。由于正方体有6个面，每个面的面积为a²（其中a为边长），所以正方体的表面积为6a²             </p>             <p>               &emsp;&emsp;&emsp;（2）               <strong> 体积：</strong               >正方体的体积是其底面积乘以高。由于正方体的底面和高都是边长a，所以其体积为<span                 >a^{3} = a \\times a \\times a</span               >               3             </p>             <br />             <h4>&emsp;&emsp;5.&emsp; 对称性：</h4>             <p>               &emsp;&emsp;正方体具有高度的对称性，包括中心对称、轴对称和面对称。具体来说，正方体关于其中心点、任何一条棱的中点所在的直线、以及任何一条面对角线所在的平面都是对称的。             </p>             <br />             <h4>&emsp;&emsp;6.&emsp; 截面：</h4>             <p>               &emsp;&emsp;&emsp;（1）               <strong> 截面：</strong               >正方体可以被不同的平面切割，形成不同的截面形状。常见的截面形状包括正方形、长方形、三角形、梯形、六边形等。特别地，当截面与正方体的三组相对棱分别平行时，截面为正方形；当截面与正方体的某一组相对棱平行但不与另外两组相对棱平行时，截面为长方形；当截面过正方体的三个顶点但不包括正方体的任何一条棱时，截面为等边三角形。             </p>             <br />             <h4>&emsp;&emsp;7.&emsp; 空间位置关系：</h4>             <p>               &emsp;&emsp;在三维空间中，正方体可以与其他几何体（如球体、圆柱体、圆锥体等）发生各种位置关系，如相离、相切、相交等。这些位置关系的研究有助于我们更深入地理解空间几何的复杂性。             </p>             <br />           </div>', '正方体知识点', 0, 1823594959465164800);
INSERT INTO `knowledge_point` VALUES (0, '  <div>             <h4>&emsp;&emsp;1.&emsp;定义：</h4>             <p>               &emsp;&emsp;正方体（或称为立方体）是一个六个面都是正方形的特殊长方体，其中所有棱的长度都相等。             </p>             <br />             <h4>&emsp;&emsp;2.&emsp; 面与棱：</h4>             <p>               &emsp;&emsp;&emsp;（1）               <strong>面：</strong>正方体有6个面，每个面都是一个正方形。             </p>             <p>               &emsp;&emsp;&emsp;（2）               <strong>棱：</strong               >正方体有12条棱，每条棱连接两个面。由于所有棱的长度都相等，因此正方体具有高度的对称性。             </p>             <p>               &emsp;&emsp;&emsp;（3）               <strong>顶点：</strong>正方体有8个顶点，每个顶点由三条棱相交而成。             </p>             <p>               &emsp;&emsp;&emsp;（4）               <strong>底面：</strong>正方体的底面是6个面中的4个面，每个底面都是正方形。             </p>             <br />             <h4>&emsp;&emsp;3.&emsp; 对角线：</h4>             <p>               &emsp;&emsp;&emsp;（1）               <strong> 面对角线：</strong               >连接正方体同一面上的两个不相邻顶点的线段称为面对角线，每条面对角线都是正方形的对角线。             </p>             <p>               &emsp;&emsp;&emsp;（2）               <strong> 体对角线：</strong               >连接正方体两个不相邻顶点的线段称为体对角线。正方体有4条体对角线，每条体对角线都连接了正方体的相对顶点。体对角线的长度可以通过三维空间中的距离公式计算，对于边长为a的正方体，体对角线的长度为<span                 >\\sqrt{a^{2} + a^{2} + a^{2}} = \\sqrt{3}a</span               >             </p>             <br />             <h4>&emsp;&emsp;4.&emsp; 表面积与体积：</h4>             <p>               &emsp;&emsp;&emsp;（1）               <strong> 表面积：</strong               >连正方体的表面积是其所有面的面积之和。由于正方体有6个面，每个面的面积为a²（其中a为边长），所以正方体的表面积为6a²             </p>             <p>               &emsp;&emsp;&emsp;（2）               <strong> 体积：</strong               >正方体的体积是其底面积乘以高。由于正方体的底面和高都是边长a，所以其体积为<span                 >a^{3} = a \\times a \\times a</span               >               3             </p>             <br />             <h4>&emsp;&emsp;5.&emsp; 对称性：</h4>             <p>               &emsp;&emsp;正方体具有高度的对称性，包括中心对称、轴对称和面对称。具体来说，正方体关于其中心点、任何一条棱的中点所在的直线、以及任何一条面对角线所在的平面都是对称的。             </p>             <br />             <h4>&emsp;&emsp;6.&emsp; 截面：</h4>             <p>               &emsp;&emsp;&emsp;（1）               <strong> 截面：</strong               >正方体可以被不同的平面切割，形成不同的截面形状。常见的截面形状包括正方形、长方形、三角形、梯形、六边形等。特别地，当截面与正方体的三组相对棱分别平行时，截面为正方形；当截面与正方体的某一组相对棱平行但不与另外两组相对棱平行时，截面为长方形；当截面过正方体的三个顶点但不包括正方体的任何一条棱时，截面为等边三角形。             </p>             <br />             <h4>&emsp;&emsp;7.&emsp; 空间位置关系：</h4>             <p>               &emsp;&emsp;在三维空间中，正方体可以与其他几何体（如球体、圆柱体、圆锥体等）发生各种位置关系，如相离、相切、相交等。这些位置关系的研究有助于我们更深入地理解空间几何的复杂性。             </p>             <br />           </div>', '正方体知识点', 0, 1824617623197065216);
INSERT INTO `knowledge_point` VALUES (1, '<div>             <h4>&emsp;&emsp;1.&emsp;定义与性质：</h4>             <p>               &emsp;&emsp;&emsp;（1）               <strong> 定义：</strong               >长方体是一个有六个矩形面的多面体，其中每个面都是矩形，并且相对的面完全相同。             </p>             <p>               &emsp;&emsp;&emsp;（2）               <strong> 顶点：</strong>长方体有8个顶点，每个顶点由三条棱相交而成。             </p>             <p>               &emsp;&emsp;&emsp;（3）               <strong> 棱：</strong               >长方体有12条棱，每条棱都是直线段，并且与四个面相交。其中，有4条棱的长度相等且平行于长方体的长度方向，另外4条棱长度相等且平行于宽度方向，最后4条棱长度相等且平行于高度方向。             </p>             <p>               &emsp;&emsp;&emsp;（4）               <strong> 面：</strong>长方体有6个面，每个面都是矩形。相对的两个面面积相等且平行。             </p>              <br />             <h4>&emsp;&emsp;2.&emsp; 体积与表面积：</h4>             <p>               &emsp;&emsp;&emsp;（1）               <strong>体积：</strong               >长方体的体积V可以通过其三个维度（长度l、宽度w、高度h）的乘积来计算，即V = l × w × h。             </p>             <p>               &emsp;&emsp;&emsp;（2）               <strong>表面积：</strong               >长方体的表面积A是其所有外表面面积的总和。每个面的面积是lw、lw或wh（取决于面是如何由长方体的维度定义的）。因此，总表面积A               = 2lw + 2lh + 2wh。             </p>              <br />             <h4>&emsp;&emsp;3.&emsp; 对角线</h4>             <p>               &emsp;&emsp;&emsp;（1）               <strong> 空间对角线：</strong               >连接长方体任意两个不相邻顶点的线段称为长方体的空间对角线。其长度d可以通过三维空间中的距离公式计算，即d               = √(l^2 + w^2 + h^2)。             </p>             <p>               &emsp;&emsp;&emsp;（2）               <strong> 面对角线：</strong               >在长方体的每个面上，连接非相邻两个顶点的线段称为面对角线。每个面的面对角线长度可以通过二维空间中的勾股定理计算。             </p>             <br />             <h4>&emsp;&emsp;4.&emsp; 性质与定理</h4>             <p>               &emsp;&emsp;&emsp;（1）               <strong> 平行性质：</strong>长方体的对棱平行且等长。             </p>             <p>               &emsp;&emsp;&emsp;（2）               <strong> 垂直性质：</strong>长方体的相邻面互相垂直。             </p>             <p>               &emsp;&emsp;&emsp;（3）               <strong> 截面性质：</strong>长方体的任何非平行于面的截面都是矩形。             </p>             <p>               &emsp;&emsp;&emsp;（4）               <strong> 三视图：</strong               >从长方体的正面、上面和侧面看到的图形分别是矩形，这些图形称为长方体的三视图。             </p>           </div>', '长方体知识点', 0, 1822964565643108352);
