INSERT INTO `knowledge_point` VALUES (1, '<div>             <h4>&emsp;&emsp;1.&emsp;定义与性质：</h4>             <p>               &emsp;&emsp;&emsp;（1）               <strong> 定义：</strong               >长方体是一个有六个矩形面的多面体，其中每个面都是矩形，并且相对的面完全相同。             </p>             <p>               &emsp;&emsp;&emsp;（2）               <strong> 顶点：</strong>长方体有8个顶点，每个顶点由三条棱相交而成。             </p>             <p>               &emsp;&emsp;&emsp;（3）               <strong> 棱：</strong               >长方体有12条棱，每条棱都是直线段，并且与四个面相交。其中，有4条棱的长度相等且平行于长方体的长度方向，另外4条棱长度相等且平行于宽度方向，最后4条棱长度相等且平行于高度方向。             </p>             <p>               &emsp;&emsp;&emsp;（4）               <strong> 面：</strong>长方体有6个面，每个面都是矩形。相对的两个面面积相等且平行。             </p>              <br />             <h4>&emsp;&emsp;2.&emsp; 体积与表面积：</h4>             <p>               &emsp;&emsp;&emsp;（1）               <strong>体积：</strong               >长方体的体积V可以通过其三个维度（长度l、宽度w、高度h）的乘积来计算，即V = l × w × h。             </p>             <p>               &emsp;&emsp;&emsp;（2）               <strong>表面积：</strong               >长方体的表面积A是其所有外表面面积的总和。每个面的面积是lw、lw或wh（取决于面是如何由长方体的维度定义的）。因此，总表面积A               = 2lw + 2lh + 2wh。             </p>              <br />             <h4>&emsp;&emsp;3.&emsp; 对角线</h4>             <p>               &emsp;&emsp;&emsp;（1）               <strong> 空间对角线：</strong               >连接长方体任意两个不相邻顶点的线段称为长方体的空间对角线。其长度d可以通过三维空间中的距离公式计算，即d               = √(l^2 + w^2 + h^2)。             </p>             <p>               &emsp;&emsp;&emsp;（2）               <strong> 面对角线：</strong               >在长方体的每个面上，连接非相邻两个顶点的线段称为面对角线。每个面的面对角线长度可以通过二维空间中的勾股定理计算。             </p>             <br />             <h4>&emsp;&emsp;4.&emsp; 性质与定理</h4>             <p>               &emsp;&emsp;&emsp;（1）               <strong> 平行性质：</strong>长方体的对棱平行且等长。             </p>             <p>               &emsp;&emsp;&emsp;（2）               <strong> 垂直性质：</strong>长方体的相邻面互相垂直。             </p>             <p>               &emsp;&emsp;&emsp;（3）               <strong> 截面性质：</strong>长方体的任何非平行于面的截面都是矩形。             </p>             <p>               &emsp;&emsp;&emsp;（4）               <strong> 三视图：</strong               >从长方体的正面、上面和侧面看到的图形分别是矩形，这些图形称为长方体的三视图。             </p>           </div>', '长方体知识点', 0, 1823220477037481984);
