INSERT INTO `knowledge_point` VALUES (1, '<div>             <h4>&emsp;&emsp;1.&emsp;定义与性质：</h4>             <p>               &emsp;&emsp;&emsp;（1）               <strong> 定义：</strong               >长方体是一个有六个矩形面的多面体，其中每个面都是矩形，并且相对的面完全相同。             </p>             <p>               &emsp;&emsp;&emsp;（2）               <strong> 顶点：</strong>长方体有8个顶点，每个顶点由三条棱相交而成。             </p>             <p>               &emsp;&emsp;&emsp;（3）               <strong> 棱：</strong               >长方体有12条棱，每条棱都是直线段，并且与四个面相交。其中，有4条棱的长度相等且平行于长方体的长度方向，另外4条棱长度相等且平行于宽度方向，最后4条棱长度相等且平行于高度方向。             </p>             <p>               &emsp;&emsp;&emsp;（4）               <strong> 面：</strong>长方体有6个面，每个面都是矩形。相对的两个面面积相等且平行。             </p>              <br />             <h4>&emsp;&emsp;2.&emsp; 体积与表面积：</h4>             <p>               &emsp;&emsp;&emsp;（1）               <strong>体积：</strong               >长方体的体积V可以通过其三个维度（长度l、宽度w、高度h）的乘积来计算，即V = l × w × h。             </p>             <p>               &emsp;&emsp;&emsp;（2）               <strong>表面积：</strong               >长方体的表面积A是其所有外表面面积的总和。每个面的面积是lw、lw或wh（取决于面是如何由长方体的维度定义的）。因此，总表面积A               = 2lw + 2lh + 2wh。             </p>              <br />             <h4>&emsp;&emsp;3.&emsp; 对角线</h4>             <p>               &emsp;&emsp;&emsp;（1）               <strong> 空间对角线：</strong               >连接长方体任意两个不相邻顶点的线段称为长方体的空间对角线。其长度d可以通过三维空间中的距离公式计算，即d               = √(l^2 + w^2 + h^2)。             </p>             <p>               &emsp;&emsp;&emsp;（2）               <strong> 面对角线：</strong               >在长方体的每个面上，连接非相邻两个顶点的线段称为面对角线。每个面的面对角线长度可以通过二维空间中的勾股定理计算。             </p>             <br />             <h4>&emsp;&emsp;4.&emsp; 性质与定理</h4>             <p>               &emsp;&emsp;&emsp;（1）               <strong> 平行性质：</strong>长方体的对棱平行且等长。             </p>             <p>               &emsp;&emsp;&emsp;（2）               <strong> 垂直性质：</strong>长方体的相邻面互相垂直。             </p>             <p>               &emsp;&emsp;&emsp;（3）               <strong> 截面性质：</strong>长方体的任何非平行于面的截面都是矩形。             </p>             <p>               &emsp;&emsp;&emsp;（4）               <strong> 三视图：</strong               >从长方体的正面、上面和侧面看到的图形分别是矩形，这些图形称为长方体的三视图。             </p>           </div>', '长方体知识点', 0, 1824617623197065216);
INSERT INTO `knowledge_point` VALUES (2, '1. 定义与性质 定义：圆柱是一个由两个平行、等大且不相交的圆面以及连接这两个圆面的侧面围成的几何体。 底面：圆柱有两个底面，它们是两个平行的圆。 侧面：圆柱的侧面是一个曲面，可以展开成一个矩形（当底面垂直于侧面时）或平行四边形（当底面不垂直于侧面时，但通常我们考虑的是垂直于侧面的情况）。 高：圆柱的高是从一个底面圆心到另一个底面圆心的垂直距离。 母线：圆柱的母线是连接底面圆上任意一点与顶面圆上（不通过圆心）一点的线段，且这些线段都平行于底面圆的直径。 2. 体积与表面积 体积：圆柱的体积V可以通过底面积乘以高来计算，即V = πr²h，其中r是底面圆的半径，h是圆柱的高。 表面积：圆柱的表面积A包括两个底面的面积和侧面的面积。侧面的面积可以通过底面圆的周长乘以高来计算，即侧面积 = 2πrh。因此，总表面积A = 2πr² + 2πrh。 3. 性质与定理 平行性质：圆柱的底面圆是平行的，且母线与底面圆平行（或说母线垂直于底面圆的平面）。 垂直性质：圆柱的高垂直于底面圆。 截面性质：当用一个平面去截圆柱时，截面可能是圆（当平面与底面平行时）、椭圆（当平面与底面不平行也不与母线平行时）或矩形（当平面与底面垂直时，此时截面为圆柱的轴截面，且矩形的长是圆柱的母线长，宽是底面圆的直径）。 4. 展开图 圆柱的侧面展开图是一个矩形，其长等于底面圆的周长（2πr），宽等于圆柱的高（h）。 两个底面展开后是两个等大的圆。', '圆柱知识点内容', 0, 1822964565643108352);
