INSERT INTO `knowledge_point` VALUES (4, '1. 定义与性质 定义：棱锥是由一个多边形底面、一个顶点以及连接这个顶点和底面各顶点的侧棱所围成的多面体。 底面：棱锥的底面是一个多边形。 顶点：棱锥有一个顶点，它不在底面上。 侧棱：棱锥的侧棱是连接顶点和底面各顶点的线段。所有侧棱的长度可以相等（等边棱锥），也可以不相等。 侧面：棱锥的侧面是由侧棱和底面各边（或其延长线）围成的三角形。 高：棱锥的高是从顶点到底面所在平面的垂线段。特别地，当底面是三角形时，棱锥的高也称为斜高，它是从顶点到底面三角形一边的垂线段的长度。 2. 体积与表面积 体积：棱锥的体积V可以通过底面积乘以高再除以3来计算，即V = (1/3)Bh，其中B是底面的面积，h是棱锥的高。 表面积：棱锥的表面积A包括底面的面积和所有侧面的面积之和。具体计算时，需要分别求出每个侧面的面积（三角形面积），然后相加，再加上底面的面积。 3. 性质与定理 平行性质：棱锥的侧棱所在的直线都相交于一点（即顶点），但它们之间并不平行。 垂直性质：棱锥的高垂直于底面。 截面性质：当用一个平面去截棱锥时，截面可能是多边形（如三角形、四边形等），具体形状取决于平面与棱锥的交线。特别地，当截面平行于底面时，截面是一个与底面相似的多边形。 4. 特殊棱锥 正棱锥：底面是正多边形，且顶点在底面的射影是底面正多边形的中心的棱锥。正棱锥的侧棱长度相等，侧面是全等的等腰三角形。 斜棱锥：侧棱不垂直于底面的棱锥。 直棱锥：侧棱垂直于底面的棱锥。特别地，当底面是三角形时，直棱锥也称为四面体。', '棱锥知识点', 0, 1823595269650722816);
INSERT INTO `knowledge_point` VALUES (5, '1. 定义与性质 定义：球体是一个连续曲面的立体图形，由空间中所有与球心距离等于半径的点组成。 球心：球体的中心点，称为球心。 半径：从球心到球体表面任意一点的距离称为半径，记作r。 直径：经过球心且两端都在球体表面上的线段称为直径，其长度是半径的两倍，即2r。 球面：球体的表面是一个连续曲面，称为球面。 2. 体积与表面积 体积：球体的体积V可以通过公式V=  3 4 ​  πr  3  计算，其中r是球体的半径。 表面积：球体的表面积A可以通过公式A=4πr  2  计算，其中r是球体的半径。 3. 性质与定理 对称性：球体是高度对称的几何体，任何经过球心的直线都可以将球体分为两个完全相等的部分。 截面性质：用一个平面去截球体，截面可能是一个圆（当平面与球心不重合时）或一个点（当平面经过球心时）。特别地，当截面是圆时，该圆的半径小于或等于球体的半径，且截面圆的圆心到球心的距离与截面圆的半径和球体的半径之间满足勾股定理。 外接与内切：球体可以与多面体（如正方体、正四面体等）有外接或内切的关系。外接球体是指多面体的所有顶点都在球体表面上的球体；内切球体是指多面体的所有面都与球体相切的球体。', '球体知识点', 0, 1822964565643108352);
INSERT INTO `knowledge_point` VALUES (5, '1. 定义与性质 定义：球体是一个连续曲面的立体图形，由空间中所有与球心距离等于半径的点组成。 球心：球体的中心点，称为球心。 半径：从球心到球体表面任意一点的距离称为半径，记作r。 直径：经过球心且两端都在球体表面上的线段称为直径，其长度是半径的两倍，即2r。 球面：球体的表面是一个连续曲面，称为球面。 2. 体积与表面积 体积：球体的体积V可以通过公式V=  3 4 ​  πr  3  计算，其中r是球体的半径。 表面积：球体的表面积A可以通过公式A=4πr  2  计算，其中r是球体的半径。 3. 性质与定理 对称性：球体是高度对称的几何体，任何经过球心的直线都可以将球体分为两个完全相等的部分。 截面性质：用一个平面去截球体，截面可能是一个圆（当平面与球心不重合时）或一个点（当平面经过球心时）。特别地，当截面是圆时，该圆的半径小于或等于球体的半径，且截面圆的圆心到球心的距离与截面圆的半径和球体的半径之间满足勾股定理。 外接与内切：球体可以与多面体（如正方体、正四面体等）有外接或内切的关系。外接球体是指多面体的所有顶点都在球体表面上的球体；内切球体是指多面体的所有面都与球体相切的球体。', '球体知识点', 0, 1823159034694897664);
