INSERT INTO `knowledge_point` VALUES (5, '1. 定义与性质 定义：球体是一个连续曲面的立体图形，由空间中所有与球心距离等于半径的点组成。 球心：球体的中心点，称为球心。 半径：从球心到球体表面任意一点的距离称为半径，记作r。 直径：经过球心且两端都在球体表面上的线段称为直径，其长度是半径的两倍，即2r。 球面：球体的表面是一个连续曲面，称为球面。 2. 体积与表面积 体积：球体的体积V可以通过公式V=  3 4 ​  πr  3  计算，其中r是球体的半径。 表面积：球体的表面积A可以通过公式A=4πr  2  计算，其中r是球体的半径。 3. 性质与定理 对称性：球体是高度对称的几何体，任何经过球心的直线都可以将球体分为两个完全相等的部分。 截面性质：用一个平面去截球体，截面可能是一个圆（当平面与球心不重合时）或一个点（当平面经过球心时）。特别地，当截面是圆时，该圆的半径小于或等于球体的半径，且截面圆的圆心到球心的距离与截面圆的半径和球体的半径之间满足勾股定理。 外接与内切：球体可以与多面体（如正方体、正四面体等）有外接或内切的关系。外接球体是指多面体的所有顶点都在球体表面上的球体；内切球体是指多面体的所有面都与球体相切的球体。', '球体知识点', 0, 1823201440844869632);
