INSERT INTO `knowledge_point` VALUES (10, '  <div>           <img src=\"/tipsContent/course2/3.png\" alt=\"\" style=\"width: 200px\">         </div>', '圆锥体展开图解', 0, 1824617623197065216);
INSERT INTO `knowledge_point` VALUES (11, '<p>            1. 扇形的定义            圆心角：顶点在圆心的角称为圆心角。扇形的圆心角通常表示为θ（单位为弧度或度）。            半径：连接圆心和圆上任意一点的线段称为半径，记作r。            2. 弧长公式            弧长l与圆心角θ（以弧度为单位）和半径r的关系为：            l=rθ            如果圆心角θ以度为单位，则弧长公式为：            l=            180            πrθ            ​             3. 扇形面积公式            扇形面积S与圆心角θ（以弧度为单位）和半径r的关系为：            S=            2            1            ​            r            2            θ            如果圆心角θ以度为单位，则扇形面积公式为：            S=            360            πr            2            θ            ​             4. 扇形与整个圆的关系            一个完整的圆（圆心角为2π或360            ∘            ）的面积为πr            2            。            因此，扇形面积占整个圆面积的比例为            2π            θ            ​            （当θ以弧度为单位）或            360            θ            ​            （当θ以度为单位）。            5. 扇形的周长            扇形的周长C由两条半径和弧长组成，即：            C=2r+l=2r+rθ=r(2+θ)(当θ以弧度为单位)            或            C=2r+            180            πrθ            ​            (当θ以度为单位)            这些公式和定义是理解和解决扇形相关问题的基础。          </p>', '扇形知识点', 0, 1822964565643108352);
