INSERT INTO `knowledge_point` VALUES (15, '  <div >           <p>             三垂线定理是立体几何的重要定理之一，平面内的一条直线，如果和这个平面的一条斜线的射影垂直，那么它也就和这条斜线垂直，三垂线定理通过平面斜线的射影与平面内一直线的垂直关系来判定斜线与平面内一条直线垂直，由于定理中涉及三条与平面内已知直线有垂直关系的直线（如图1，PA⊥平面α，PB⊥a，AB⊥a），故称为三垂线定理。           </p>           <img src=\"http://121.40.154.188:8080/courseware/img/955b6e5c-7c6b-482a-aeeb-d10a85b0c229.png\" alt=\"\" style=\"width: 200px;\">         </div>', '三垂线定理', 0, 1822964565643108352);
INSERT INTO `knowledge_point` VALUES (15, '  <div >           <p>             三垂线定理是立体几何的重要定理之一，平面内的一条直线，如果和这个平面的一条斜线的射影垂直，那么它也就和这条斜线垂直，三垂线定理通过平面斜线的射影与平面内一直线的垂直关系来判定斜线与平面内一条直线垂直，由于定理中涉及三条与平面内已知直线有垂直关系的直线（如图1，PA⊥平面α，PB⊥a，AB⊥a），故称为三垂线定理。           </p>           <img src=\"http://121.40.154.188:8080/courseware/img/955b6e5c-7c6b-482a-aeeb-d10a85b0c229.png\" alt=\"\" style=\"width: 200px;\">         </div>', '三垂线定理', 0, 1823159034694897664);
