INSERT INTO `knowledge_test` VALUES (1, 1822964565643108352, 0, '[[FALSE,FALSE,TRUE,FALSE],[TRUE,FALSE,FALSE,FALSE]]', NULL, '设上底面半径为3R，下底面半径为5R，母线长为2L，则中截面半径为4R，分成的两个圆台的母线长均为L，则根据圆台面积公式，可知S₁=π(4R+3R)L，S₂=π(4R+5R)L，故上下两部分侧面积的比为7:9。 | 设扇形半径为R，l为扇形弧长，也为圆锥底面周长，则S₁=1/2lR=1/2|α|R²=3/8πR²，设圆锥底面圆半径为r。2πr=|α|R=3/4πR，r=3/8R，圆S₂=πr²=9/64πR²，故表面积S₃=S₁+S₂ = 33/64πR²。故二者之比为11:8。', '[{\"id\":0,\"img\":\"/question/course2Q1.png\",\"A\":\"A. 3:5\",\"B\":\"B. 9:25\",\"C\":\"C. 5：√41\",\"D\":\"D. 7:9\",\"name\":\"q1\"},{\"id\":1,\"img\":\"/question/course2Q2.png\",\"A\":\"A. 11:8\",\"B\":\"B. 3:8\",\"C\":\"C. 8:3\",\"D\":\"D. 13:8\",\"name\":\"q2\"}]', 0, 'CA');
