INSERT INTO `knowledge_test` VALUES (2, 1822964565643108352, 0, '[[FALSE,TRUE,FALSE,FALSE],[FALSE,FALSE,TRUE,FALSE]]', NULL, '如果α⊥B，则α内与两平面的交线平行的直线都平行于面β，故可推断出 A命题正确；选项中α内与两平面的交线平行的直线都平行于面β,故B命题错误；根据平面与平面垂直的判定定理可知C命题正确；根据两个平面垂直的性质推断出D命题正确。综上所述，故选B。 | 垂直于同一平面的两条直线平行。', '[{\"id\":0,\"img\":\"/question/course3Q1.png\",\"A\":\"A. 如果α⊥β，那么α内一定存在直线平行于平面β\",\"B\":\"B. 如果α⊥β，那么α内所有直线都垂直于平面β\",\"C\":\"C. 如果平面α不垂直平面β，那么α内一定不存在直线垂直于平面β\",\"D\":\"D. 如果α⊥γ，β⊥γ，α∩β=l，那么l⊥γ\",\"name\":\"q1\"},{\"id\":1,\"img\":\"/question/course3Q2.png\",\"A\":\"A. 平行于同一平面的两条直线平行\",\"B\":\"B. 与某一平面成等角的两条直线平行\",\"C\":\"C. 垂直于同一平面的两条直线平行\",\"D\":\"D. 垂直于同一条直线的两条直线平行\",\"name\":\"q2\"}]', 0, NULL);
INSERT INTO `knowledge_test` VALUES (2, 1823159034694897664, 0, '[[FALSE,TRUE,FALSE,FALSE],[FALSE,FALSE,TRUE,FALSE]]', NULL, '如果α⊥B，则α内与两平面的交线平行的直线都平行于面β，故可推断出 A命题正确；选项中α内与两平面的交线平行的直线都平行于面β,故B命题错误；根据平面与平面垂直的判定定理可知C命题正确；根据两个平面垂直的性质推断出D命题正确。综上所述，故选B。 | 垂直于同一平面的两条直线平行。', '[{\"id\":0,\"img\":\"/question/course3Q1.png\",\"A\":\"A. 如果α⊥β，那么α内一定存在直线平行于平面β\",\"B\":\"B. 如果α⊥β，那么α内所有直线都垂直于平面β\",\"C\":\"C. 如果平面α不垂直平面β，那么α内一定不存在直线垂直于平面β\",\"D\":\"D. 如果α⊥γ，β⊥γ，α∩β=l，那么l⊥γ\",\"name\":\"q1\"},{\"id\":1,\"img\":\"/question/course3Q2.png\",\"A\":\"A. 平行于同一平面的两条直线平行\",\"B\":\"B. 与某一平面成等角的两条直线平行\",\"C\":\"C. 垂直于同一平面的两条直线平行\",\"D\":\"D. 垂直于同一条直线的两条直线平行\",\"name\":\"q2\"}]', 0, NULL);
